```typescript
async use(req: Request, res: Response, next: NextFunction) {
  const authHeaders = req.headers.authorization;

  if (authHeaders && (authHeaders as string).split(' ')[1]) {
    // Extract token from "Bearer <token>"
    const token = (authHeaders as string).split(' ')[1];

    // Verify JWT signature
    const decoded: any = jwt.verify(token, SECRET);

    // Fetch user from database
    const user = await this.userService.findById(decoded.id);

    if (!user) {
      throw new HttpException('User not found.', HttpStatus.UNAUTHORIZED);
    }

    // Attach user to request object
    req.user = user.user;
    next();
  } else {
    throw new HttpException('Not authorized.', HttpStatus.UNAUTHORIZED);
  }
}
```

**Key steps:**
1. Extracts token from `Authorization: Bearer <token>` header
2. Verifies JWT signature using `SECRET` constant
3. Decodes token to get `user.id`
4. Queries database for user by ID
5. Attaches user to `req.user` if found
6. Throws `401 UNAUTHORIZED` if token invalid or user not found

